SELECT COUNT(firmware_id) AS firmware_count
FROM firmware_versions
WHERE modem_id = 1;

SELECT type_name
FROM modem_types
WHERE modem_id = 0;

SELECT MAX(data_transfer_rate) AS max_data_transfer_rate
FROM transmission_types
WHERE transmission_name = 'GMSK';

SELECT modem_id, AVG(data_transfer_rate) AS avg_transfer_rate
FROM transmission_types
GROUP BY modem_id;

SELECT MAX(release_date) AS latest_release_date
FROM firmware_versions
WHERE modem_id = 1;

SELECT log_entry, log_level
FROM network_logs
WHERE log_level = 'error';

SELECT fv.modem_id, COUNT(fv.version_number) AS firmware_count
FROM firmware_versions AS fv
GROUP BY fv.modem_id;
